final_sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>

SELECT ?sub
       (?amount * ?itemMass AS ?kg)
       (?relUnc * ?amount * ?itemMass AS ?kgUncertainty)
WHERE {
  ?sub rdfs:subClassOf <https://www.purl.org/futuram#elvBEV_Y2020> ;
       fq:itemMass ?itemMass ;
       fq:contains [ fq:constituent <https://www.purl.org/futuram#5xxxAlAlloy> ;
                     fq:amount ?amount ;
                     fq:relativeUncertainty ?relUnc ] .
}
ORDER BY DESC(?kg)

arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT ?class ?label ?comment WHERE {
  ?class a owl:Class .
  OPTIONAL { ?class rdfs:label ?label }
  OPTIONAL { ?class rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "5xxx") || CONTAINS(LCASE(STR(?label)), "alalloy") || CONTAINS(LCASE(STR(?comment)), "5xxx"))
}

