arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
PREFIX fq:   <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT ?class ?label ?amount ?unc WHERE {
  ?class a owl:Class ;
         rdfs:label ?label ;
         fq:itemMass ?itemMass ;
         fq:contains [ fq:constituent futuram:5xxxAlAlloy ;
                       fq:amount ?amount ;
                       fq:relativeUncertainty ?unc ] .
  ?parent rdfs:label ?parentLabel .
  ?class rdfs:subClassOf ?parent .
  FILTER( CONTAINS(LCASE(STR(?label)), "battery-electric")
       && CONTAINS(STR(?label), "Y2020") )
}
ORDER BY DESC(?amount)

