PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?cls ?label ?mean ?relUnc (?mean * ?relUnc AS ?stddev)
WHERE {
  # Discover all BEV 2020 subclasses from the data (transitive closure)
  ?cls rdfs:subClassOf* ?root .
  ?root rdfs:label ?rootLabel .
  FILTER(?root = futuram:elvBEV_Y2020 || (?cls rdfs:subClassOf futuram:Product && CONTAINS(?cls_label, "battery-electric") && CONTAINS(?cls_label, "2020")))
  ?cls rdfs:label ?cls_label .
  FILTER(CONTAINS(?cls_label, "battery-electric vehicle") && CONTAINS(?cls_label, "2020"))
  OPTIONAL {
    ?cls fq:contains [ fq:constituent futuram:5xxxAlAlloy ;
                      fq:amount ?mean ;
                      fq:relativeUncertainty ?relUnc ] .
  }
}
ORDER BY DESC(?mean)

